   136→// Get offer letter HTML for viewing
   137→router.get('/offers/:id/letter', authMiddleware, async (req, res) => {
   138→  try {
   139→    // Allow both recruiter (company_id match) and candidate (candidate_id match)
   140→    const result = await pool.query(
   141→      `SELECT offer_letter_html, offer_letter_generated_at, status, candidate_signature, candidate_signed_at
   142→       FROM offers
   143→       WHERE id = $1 AND (company_id = $2 OR candidate_id = $2)`,
   144→      [req.params.id, req.user.company_id || req.user.id]
   145→    );
   146→
   147→    if (result.rows.length === 0) {
   148→      // Try candidate match specifically
   149→      const candidateResult = await pool.query(
   150→        `SELECT offer_letter_html, offer_letter_generated_at, status, candidate_signature, candidate_signed_at
   151→         FROM offers WHERE id = $1 AND candidate_id = $2`,
   152→        [req.params.id, req.user.id]
   153→      );
   154→      if (candidateResult.rows.length === 0) {
   155→        return res.status(404).json({ error: 'Offer not found' });
   156→      }
   157→      return res.json(candidateResult.rows[0]);
   158→    }
   159→
   160→    res.json(result.rows[0]);
   161→  } catch (err) {
   162→    console.error('Error fetching offer letter:', err);
   163→    res.status(500).json({ error: 'Failed to fetch offer letter' });
   164→  }
