   166→
   167→// Get all offers for recruiter's company
   168→router.get('/offers', authMiddleware, async (req, res) => {
   169→  try {
   170→    const result = await pool.query(
   171→      `SELECT o.*,
   172→        u.name as candidate_name,
   173→        u.email as candidate_email,
   174→        j.title as job_title,
   175→        r.name as recruiter_name,
   176→        CASE WHEN o.offer_letter_html IS NOT NULL THEN true ELSE false END as has_letter
   177→      FROM offers o
   178→      JOIN users u ON o.candidate_id = u.id
   179→      LEFT JOIN jobs j ON o.job_id = j.id
   180→      LEFT JOIN users r ON o.recruiter_id = r.id
