   237→// Candidate views offer (track engagement)
   238→router.post('/offers/:id/view', authMiddleware, async (req, res) => {
   239→  try {
   240→    const result = await pool.query(
   241→      `UPDATE offers
   242→       SET viewed_at = COALESCE(viewed_at, NOW()),
   243→           status = CASE WHEN status = 'sent' THEN 'viewed' ELSE status END,
   244→           updated_at = NOW()
   245→       WHERE id = $1 AND candidate_id = $2
   246→       RETURNING *`,
   247→      [req.params.id, req.user.id]
   248→    );
   249→
   250→    if (result.rows.length === 0) {
   251→      return res.status(404).json({ error: 'Offer not found' });
   252→    }
   253→
   254→    res.json(result.rows[0]);
   255→  } catch (err) {
   256→    console.error('Error marking offer as viewed:', err);
