   390→// ============================================
   391→// ONBOARDING CHECKLISTS
   392→// ============================================
   393→
   394→// Get candidate's checklists
   395→router.get('/checklists', authMiddleware, async (req, res) => {
   396→  try {
   397→    const result = await pool.query(
   398→      `SELECT * FROM onboarding_checklists
