   410→
   411→// Update checklist item completion
   412→router.post('/checklists/:id/complete', authMiddleware, async (req, res) => {
   413→  try {
   414→    const { item_id } = req.body;
   415→
   416→    const checklist = await pool.query(
   417→      'SELECT * FROM onboarding_checklists WHERE id = $1 AND candidate_id = $2',
   418→      [req.params.id, req.user.id]
   419→    );
   420→
   421→    if (checklist.rows.length === 0) {
   422→      return res.status(404).json({ error: 'Checklist not found' });
   423→    }
   424→
   425→    const completedItems = checklist.rows[0].completed_items || [];
   426→    if (!completedItems.includes(item_id)) {
   427→      completedItems.push(item_id);
   428→    }
   429→
   430→    const items = checklist.rows[0].items || [];
   431→    const allCompleted = items.every(item => completedItems.includes(item.id));
   432→
   433→    const result = await pool.query(
   434→      `UPDATE onboarding_checklists
   435→       SET completed_items = $1,
   436→           status = $2,
   437→           completed_at = $3,
   438→           updated_at = NOW()
   439→       WHERE id = $4
   440→       RETURNING *`,
   441→      [
   442→        JSON.stringify(completedItems),
   443→        allCompleted ? 'completed' : 'in_progress',
   444→        allCompleted ? new Date() : null,
   445→        req.params.id
   446→      ]
   447→    );
   448→
   449→    res.json(result.rows[0]);
   450→  } catch (err) {
   451→    console.error('Error updating checklist:', err);
   452→    res.status(500).json({ error: 'Failed to update checklist' });
   453→  }
   454→});
