   479→
   480→// Get documents for checklist
   481→router.get('/checklists/:id/documents', authMiddleware, async (req, res) => {
   482→  try {
   483→    const result = await pool.query(
   484→      `SELECT * FROM onboarding_documents
   485→       WHERE checklist_id = $1 AND candidate_id = $2
