   497→// ============================================
   498→// POST-HIRE FEEDBACK
   499→// ============================================
   500→
   501→// Create feedback survey (auto-scheduled by system)
   502→router.post('/feedback/schedule', authMiddleware, async (req, res) => {
   503→  try {
   504→    const { employee_id, day_mark } = req.body;
   505→
   506→    const questions = {
   507→      30: [
   508→        'How would you rate your onboarding experience?',
   509→        'Do you feel prepared to do your job?',
   510→        'Is there anything we could improve?'
   511→      ],
   512→      60: [
   513→        'How satisfied are you with your role?',
   514→        'Do you have the resources you need to succeed?',
   515→        'How would you rate communication with your manager?'
   516→      ],
   517→      90: [
   518→        'Would you recommend this company to a friend?',
   519→        'What has been your biggest challenge so far?',
   520→        'What has exceeded your expectations?'
   521→      ]
   522→    };
   523→
   524→    const result = await pool.query(
   525→      `INSERT INTO post_hire_feedback
   526→       (employee_id, manager_id, feedback_type, day_mark, questions, status, sent_at)
   527→       VALUES ($1, $2, $3, $4, $5, $6, NOW())
   528→       RETURNING *`,
   529→      [
   530→        employee_id,
   531→        req.user.id,
   532→        'check_in',
   533→        day_mark,
   534→        JSON.stringify(questions[day_mark] || questions[30]),
   535→        'sent'
   536→      ]
   537→    );
   538→
   539→    res.json(result.rows[0]);
   540→  } catch (err) {
   541→    console.error('Error scheduling feedback:', err);
