      city: wd.city,
      state: wd.state,
      zip: wd.zip_code,
      ssn_last_four: wd.ssn_encrypted ? '****' : 'N/A',
      generated_at: new Date().toISOString(),
      company: cl.company_name
    };

    const i9 = await upsertDocument(
      checklist_id, req.user.id, offerCompanyId,
