EMPLOYEE SITUATION:
- Annual salary: ${salary ? '$' + Number(salary).toLocaleString() : 'Not provided'}
- Filing status: ${filing_status || 'Not selected yet'}
- Multiple jobs: ${multiple_jobs ? 'Yes' : 'No'}
