        req.user.id, checklist_id
      ]);

      await completeChecklistItem(checklist_id, req.user.id, 4);
      return res.json({ success: true, wizard: result.rows[0] });
    }

    res.status(400).json({ error: 'Invalid step' });
  } catch (err) {
