          <tr><td class="label">Employer:</td><td>${escapeHtmlServer(content.employer || content.company || '')}</td></tr>
          <tr><td class="label">EIN:</td><td>${escapeHtmlServer(content.employer_ein || 'On file')}</td></tr>
