      </div>
      <div class="section">
        <p class="authorization">${escapeHtmlServer(content.acknowledgment_text || '')}</p>
      </div>
    `;
  } else {
    bodyContent = `<pre>${JSON.stringify(content, null, 2)}</pre>`;
  }

  return `<!DOCTYPE html>
<html>
<head>
